mapper.select:
SELECT group_key AS groupKey, code, name, value, sort_order AS sortOrder, use_yn AS useYn FROM codes WHERE group_key = #{groupKey}
AND tenant_id = #{tenantId}
ORDER BY sort_order ASC, code ASC

mapper.update:
UPDATE codes
   SET name       = #{name},
       value      = #{value},
       sort_order = #{sortOrder},
       use_yn     = #{useYn},
       updated_at = NOW()
 WHERE group_key  = #{groupKey}
   AND code       = #{code}

   AND tenant_id  = #{tenantId}

mapper.delete:
DELETE FROM codes
 WHERE group_key = #{groupKey}
   AND code      = #{code}

   AND tenant_id = #{tenantId}
